VALUES
  ('dietitian-moex-04164', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關心臟衰竭stage C及stage D（依據American Heart Association定義分類）之主要營養治療原 則，下列敘述何者最不適當？', '["以健康飲食、有氧運動及多喝水等進行生活型態改善", "若使用利尿劑，則視需要補充鎂及維生素B 1", "每日鈉攝取控制在2公克，水份攝取可先以每天小於2,000 c.c.為原則", "惡病質或營養狀況不佳，可考慮腸道或靜脈營養，但要注意體液進出量之平衡"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04165', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '在發生創傷（traumatic injury）或敗血症（sepsis）後，人體對蛋白質之利用及代謝會發生改 變，下列對於重症病人體內蛋白質代謝的敘述何者最不適當？', '["肌肉蛋白質會大量分解成支鏈胺基酸（branched-chain amino acids, BCAAs）以提供肌肉能量來 源", "此時肝臟會大量製造急性期蛋白質（acute-phase protein）來調控生理的損傷或感染，而製造急 性期蛋白質的原料主要來自於體內的瘦體組織（lean body mass）", "由於肌肉蛋白質大量分解，鉀、磷及鈣離子會大量從尿中流失", "病人體內容易呈現負氮平衡（negative nitrogen balance），而此現象要在控制好病人的發炎反 應後才得以改善"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04166', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關加速術後康復（enhanced recovery after surgery, ERAS）的步驟，下列敘述何者錯誤？', '["為了避免手術時發生吸入性嗆傷，術前不可給與任何型態的食物", "在腹部或大腸手術前可以給與富含碳水化合物的飲料，以促進血糖的調控並減少氮的流失", "在手術中需注意水分的補充量，避免過度補充", "術後如果胃腸道功能正常，給與固態食物飲食比給與清流質飲食佳"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04167', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '王先生在進行捷運架高工程時，不甚從高處跌落後被巨大落石壓傷，被緊急送醫後，因右側大腿粉 碎性骨折後截肢，病人因敗血症與呼吸衰竭進行急救後由急診收治外科加護病房。王先生收治後五 天，其血液動力學（hemodynamics）狀態漸漸穩定，其BMI為26，要開始進行營養支持，但仍因呼 吸衰竭持續以呼吸機支持、體內呈現酸中毒（acidosis）的狀態。下列何者為最適當的熱量需求估 算方式？', '["以indirect calorimetry的測量為基準", "每公斤體重35～40大卡", "每公斤體重25～30大卡", "每公斤體重35大卡＋500大卡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04168', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '承上題，關於王先生灌食前後的血液動力學（hemodynamics）狀態，其監控項目或標準何者錯誤？', '["血糖控制80～110 mg/dL", "mean arterial pressure（MAP）＞50 mmHg", "cardiac output", "oxygen saturation"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04169', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關tuberculosis病人之每日蛋白質建議攝取量，下列何者最適當？', '["0.6～0.8 g/kg", "0.9～1.1 g/kg", "1.2～1.5 g/kg", "1.6～2.0 g/kg"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04170', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關慢性阻塞性肺病（COPD）病人營養照護的主要目標，下列何者最不相關？', '["維持瘦肉組織與脂肪組織適當的比例", "減少藥物和營養素的交互作用", "維持水分的平衡", "預防高三酸甘油酯血症"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04171', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關酒精與癌症的敘述，下列何者最不適當？', '["酒精對食道癌而言是可改變風險因素之一", "酒精會增加罹患肝癌的風險，並增加倖存者的死亡率", "同時使用菸草和酒精會增加上消化道癌症風險", "建議女性每日酒精攝取量不超過2酒精當量"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04172', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關cancer cachexia，下列敘述何者錯誤？', '["會持續性的減輕體重其機制類似慢性飢餓狀態", "增加脂質分解並減少脂肪組織質量", "增加蛋白質分解與肌肉耗損", "增加基礎代謝率因而增加能量消耗"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04173', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '依據2019亞洲肌少症工作小組（Asian Working Group for Sarcopenia, AWGS）對肌少症之共識， 建議基層醫療可以使用下列何種問卷篩檢肌少症？', '["Mini Nutritional Assessment（MNA）", "Strength, Assistance with walking, Rising from a chair, Climbing stairs, and Falls （SARC-F）", "Malnutrition Universal Screening Tool（MUST）", "Subjective Global Assessment（SGA）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
